#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long *a = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;i++) scanf("%lld", &a[i]);
        long long *sufMin = (long long*)malloc(N*sizeof(long long));
        for(int i=N-1;i>=0;i--){
            if(i==N-1) sufMin[i]=a[i];
            else sufMin[i]= (a[i] < sufMin[i+1]) ? a[i] : sufMin[i+1];
        }
        long long ans=0;
        long long curMax=a[0], curMin=a[0];
        for(int i=0;i<N;i++){
            if(a[i]>curMax) curMax=a[i];
            if(a[i]<curMin) curMin=a[i];
            int last = (i==N-1);
            if(last || curMax <= sufMin[i+1]){
                ans += curMax - curMin;
                if(i+1<N){
                    curMax = a[i+1];
                    curMin = a[i+1];
                }
            }
        }
        printf("%lld\n", ans);
        free(a); free(sufMin);
    }
    return 0;
}

