import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long[] a = new long[N];
            for (int i = 0; i < N; i++) a[i] = fs.nextLong();
            long[] sufMin = new long[N];
            for (int i = N - 1; i >= 0; i--) {
                if (i == N - 1) sufMin[i] = a[i];
                else sufMin[i] = Math.min(a[i], sufMin[i + 1]);
            }
            long ans = 0;
            long curMax = a[0], curMin = a[0];
            for (int i = 0; i < N; i++) {
                curMax = Math.max(curMax, a[i]);
                curMin = Math.min(curMin, a[i]);
                boolean last = (i == N - 1);
                if (last || curMax <= sufMin[i + 1]) {
                    ans += curMax - curMin;
                    if (i + 1 < N) {
                        curMax = a[i + 1];
                        curMin = a[i + 1];
                    }
                }
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }

    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

