import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        suf_min = [0]*N
        for i in range(N-1, -1, -1):
            if i == N-1:
                suf_min[i] = a[i]
            else:
                suf_min[i] = min(a[i], suf_min[i+1])
        ans = 0
        cur_max = cur_min = a[0]
        for i in range(N):
            cur_max = max(cur_max, a[i])
            cur_min = min(cur_min, a[i])
            if i == N-1 or cur_max <= suf_min[i+1]:
                ans += cur_max - cur_min
                if i+1 < N:
                    cur_max = cur_min = a[i+1]
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

